def is_safe_url(target):
    """Validate that the redirect URL is safe (same host) to prevent open redirect attacks."""
    if not target:
        return False
    ref_url = urlparse(request.host_url)
    test_url = urlparse(urljoin(request.host_url, target))
    return test_url.scheme in ('http', 'https') and ref_url.netloc == test_url.netloc


def get_redirect_target():
    """Get the redirect target from the 'next' parameter or referrer."""
    # Check the 'next' query parameter first
    target = request.args.get('next') or request.form.get('next')

    # Fall back to the HTTP referrer
    if not target:
        target = request.referrer

    # Validate the target URL
    if target and is_safe_url(target):
        return target

    return None


def redirect_back(default='home', **kwargs):
    """Redirect the user back to their intended destination or a default page."""
    target = get_redirect_target()
    if target:
        return redirect(target)
    return redirect(url_for(default, **kwargs))


def login_required(f):
    """Decorator to protect routes that require authentication."""
    @wraps(f)
    def decorated_function(*args, **kwargs):
        if 'username' not in session:
            # Store the intended destination so we can redirect after login
            next_url = request.url
            return redirect(url_for('login', next=next_url))
        return f(*args, **kwargs)
    return decorated_function


@app.route('/')
def home():
    if 'username' in session:
        return render_template_string(
            PAGE_TEMPLATE,
            title='Home',
            message='This is the home page. You are logged in!',
            session=session
        )
    return render_template_string(
        PAGE_TEMPLATE,
        title='Home',
        message='This is the home page. <a href="/login">Login</a> to access protected pages.',
        session=session
    )


@app.route('/login', methods=['GET', 'POST'])
def login():
    # If already logged in, redirect to intended destination or home
    if 'username' in session:
        return redirect_back(default='home')

    error = None
    next_url = request.args.get('next', '')

    if request.method == 'POST':
        username = request.form.get('username', '')
        password = request.form.get('password', '')
        next_url = request.form.get('next', '')

        if username in USERS and USERS[username] == password:
            # Successful login
            session['username'] = username
            session['logged_in'] = True

            # Redirect to the intended destination
            if next_url and is_safe_url(next_url):
                return redirect(next_url)
            return redirect(url_for('dashboard'))
        else:
            error = 'Invalid username or password.'

    return render_template_string(
        LOGIN_TEMPLATE,
        error=error,
        next_url=next_url
    )


@app.route('/logout')
def logout():
    session.clear()
    return redirect(url_for('home'))


