@app.route('/test-redirect-safety')
def test_redirect_safety():
    """Demonstrates that unsafe redirects are blocked."""
    results = {
        '/dashboard': is_safe_url('/dashboard'),
        '/profile?tab=info': is_safe_url('/profile?tab=info'),
        'http://evil.com/steal': is_safe_url('http://evil.com/steal'),
        '//evil.com/phish': is_safe_url('//evil.com/phish'),
        'javascript:alert(1)': is_safe_url('javascript:alert(1)'),
    }
    output = '<h2>Redirect Safety Test</h2><ul>'
    for url, safe in results.items():
        color = 'green' if safe else 'red'
        status = 'SAFE' if safe else 'BLOCKED'
        output += f'<li style="color:{color};">{url} → {status}</li>'
    output += '</ul><a href="/">Back to Home</a>'
    return output


